/**
 * Evidence Engine — integrity module
 *
 * AUTO-GENERATED by Phoenix VCS
 * Determines required evidence per risk tier and binds evidence to canon/IU pairs.
 */

export type RiskTier = 'low' | 'medium' | 'high' | 'critical';

export interface EvidenceBinding {
  canonId: number;
  iuId: string;
  artifactHash: string;
  timestamp: number;
}

const EVIDENCE_BY_TIER: Record<RiskTier, string[]> = {
  low: ['typecheck', 'lint', 'boundary_validation'],
  medium: ['typecheck', 'lint', 'boundary_validation', 'unit_tests'],
  high: ['typecheck', 'lint', 'boundary_validation', 'unit_tests', 'property_tests', 'threat_note', 'static_analysis'],
  critical: ['typecheck', 'lint', 'boundary_validation', 'unit_tests', 'property_tests', 'threat_note', 'static_analysis', 'human_signoff'],
};

export class EvidenceEngine {
  private bindings: EvidenceBinding[] = [];

  getRequirements(riskTier: RiskTier): string[] {
    return [...EVIDENCE_BY_TIER[riskTier]];
  }

  bindEvidence(canonId: number, iuId: string, artifactHash: string): EvidenceBinding {
    const binding: EvidenceBinding = {
      canonId,
      iuId,
      artifactHash,
      timestamp: Date.now(),
    };
    this.bindings.push(binding);
    return binding;
  }

  getBindings(): EvidenceBinding[] {
    return [...this.bindings];
  }
}

export function createEvidenceEngine(): EvidenceEngine {
  return new EvidenceEngine();
}

